function groupModels(models) {
  const groups = {};
  models.forEach(m => {
    const g = getModelGroup(m);
    if (!groups[g]) groups[g] = [];
    groups[g].push(m);
  });
  // Sort groups: known first, "其他" last
  const sorted = {};
  Object.keys(groups).sort((a, b) => {
    if (a === '其他模型') return 1;
    if (b === '其他模型') return -1;
    return a.localeCompare(b);
  }).forEach(k => sorted[k] = groups[k]);
  return sorted;
}

