let modelSearchOpen = false;
let modelGroupStates = {}; // group name → open/closed
let currentModelTab = 'all';

function changeModelTab(tab) {
  currentModelTab = tab;
  // 切换 active 样式
  document.querySelectorAll('.model-filter-tab').forEach(el => {
    const isClickedTab = el.getAttribute('onclick')?.includes(`'${tab}'`);
    el.classList.toggle('active', isClickedTab);
  });
  filterModelPanel();
}

