function toggleKeyVisibility() {
  const keyInput = document.getElementById('pf-key');
  const btn = document.getElementById('pf-key-toggle');
  if (!keyInput) return;
  if (keyInput.type === 'password') {
    keyInput.type = 'text';
    if (btn) btn.innerHTML = EYE_SVG_CLOSE;
  } else {
    keyInput.type = 'password';
    if (btn) btn.innerHTML = EYE_SVG_OPEN;
  }
}

function cleanProviderApiPath(value) {
  const raw = String(value || '').trim();
  if (!raw || raw === '/') return '';
  return '/' + raw.replace(/^\/+/, '').replace(/\/+$/, '');
}

function isGeneratedProviderApiPath(apiFormat, apiPath) {
  const path = cleanProviderApiPath(apiPath).toLowerCase();
  if (!path) return false;
  if (apiFormat === 'openai') {
    return [
      '/v1/chat/completions',
      '/api/v1/chat/completions',
      '/v1/responses',
      '/api/v1/responses',
    ].includes(path);
  }
  return path === '/v1/messages' || path === '/api/v1/messages';
}

function displayProviderApiPath(apiFormat, apiPath) {
  const path = cleanProviderApiPath(apiPath);
  return isGeneratedProviderApiPath(apiFormat, path) ? '' : path;
}

function providerEndpointParts(baseUrl, apiFormat, pathValue) {
  let apiHost = baseUrl;
  let parsedPath = '';
  try {
    const url = new URL(String(baseUrl || '').startsWith('http') ? baseUrl : 'https://' + baseUrl);
    apiHost = url.origin;
    parsedPath = cleanProviderApiPath(url.pathname);
  } catch {
    // Keep the raw host; runtime normalization will still do a final guard.
  }

  const apiPath = parsedPath || displayProviderApiPath(apiFormat, pathValue);

  return { apiHost, apiPath };
}

function providerEndpointDisplayUrl(apiHost, apiPath, apiFormat) {
  const host = String(apiHost || '').trim().replace(/\/+$/, '');
  if (!host) return '';
  const path = displayProviderApiPath(apiFormat, apiPath);
  return `${host}${path}`;
}

function onFormatChange() {
  const fmtEl = document.getElementById('pf-format');
  if (!fmtEl) return;
  const fmt = fmtEl.value;
  const badge = document.getElementById('pf-format-badge');

  // 同步 API 格式徽章（兼容旧版徽章元素）
  if (badge) badge.textContent = fmt === 'openai' ? 'OpenAI' : 'Anthropic';

  // 同步下拉按钮 UI（锁定态显示锁定值，自动态显示带"自动"后缀）
  const lockKey = fmtEl.dataset ? fmtEl.dataset.locked : null;
  if (lockKey === '1') {
    syncFormatDropdownUi(fmt);
  } else {
    syncFormatDropdownUi('auto');
  }

  // 不再根据格式自动改 apiPath；默认端点只在后端发起请求时临时推断。

  // Ensure current selected models are in the list
  selectedModels.forEach(m => {
    if (m && !activeModelsList.includes(m)) {
      activeModelsList.unshift(m);
    }
  });
  modelGroupStates = {};
  filterModelPanel();
}

// 根据用户填写的 API 地址自动推断格式
function autoDetectFormatFromHost(hostValue) {
  if (!hostValue) return 'anthropic';
  const v = hostValue.toLowerCase();
  if (v.includes('anthropic') || v.includes('/v1/messages')) {
    return 'anthropic';
  }
  // 命中 OpenAI 特征：路径含 chat/completions、域名含 openai、含 /v1 路径
  if (v.includes('openai')
      || v.includes('dashscope')
      || v.includes('qwen')
      || v.includes('chat/completions')
      || v.includes('/compatible-mode')
      || v.includes('/v1/chat')
      || /\/v1\/?(\?|$)/.test(v)) {
    return 'openai';
  }
  return 'anthropic';
}

// 用户输入 URL 时自动识别 + 更新徽章
function onHostChange() {
  const hostEl = document.getElementById('pf-host');
  const fmtEl = document.getElementById('pf-format');
  if (!hostEl || !fmtEl) return;
  // 用户手动锁定为 anthropic / openai 时，URL 变化不自动覆盖
  const locked = fmtEl.dataset && fmtEl.dataset.locked === '1';
  if (locked) return;
  const detected = autoDetectFormatFromHost(hostEl.value);
  if (fmtEl.value !== detected) {
    fmtEl.value = detected;
    onFormatChange();
  }
  // 同步下拉按钮的当前选中态（自动识别模式下随 URL 实时变）
  syncFormatDropdownUi('auto');
}

// 切换下拉显隐
function toggleFormatDropdown(event) {
  if (event) event.stopPropagation();
  const dd = document.getElementById('pfFormatDropdown');
  const trigger = document.getElementById('pfFormatTrigger');
  if (!dd) return;
  const isOpen = dd.style.display === 'flex';
  if (isOpen) {
    dd.style.display = 'none';
    if (trigger) trigger.setAttribute('aria-expanded', 'false');
  } else {
    dd.style.display = 'flex';
    if (trigger) trigger.setAttribute('aria-expanded', 'true');
  }
}

// 用户在下拉里选了某个格式
function pickApiFormat(format, event) {
  if (event) event.stopPropagation();
  const fmtEl = document.getElementById('pf-format');
  const hostEl = document.getElementById('pf-host');
  if (!fmtEl) return;

  if (format === 'auto') {
    // 切回自动识别：解锁 + 立刻按 URL 重算
    fmtEl.dataset.locked = '0';
    if (hostEl) {
      const detected = autoDetectFormatFromHost(hostEl.value);
      fmtEl.value = detected;
      onFormatChange();
    }
    syncFormatDropdownUi('auto');
  } else {
    // 锁定为 anthropic / openai
    fmtEl.value = format;
    fmtEl.dataset.locked = '1';
    onFormatChange();
    syncFormatDropdownUi(format);
  }
  // 关闭下拉
  const dd = document.getElementById('pfFormatDropdown');
  if (dd) dd.style.display = 'none';
  const trigger = document.getElementById('pfFormatTrigger');
  if (trigger) trigger.setAttribute('aria-expanded', 'false');
}

// 同步下拉按钮的显示（label + 选项高亮）
function syncFormatDropdownUi(activeFormat) {
  const fmtEl = document.getElementById('pf-format');
  const labelEl = document.getElementById('pfFormatTriggerLabel');
  if (!fmtEl || !labelEl) return;
  // 决定 label 文本：auto 时按 URL 实时显示，锁定时显示锁定值
  let display;
  if (activeFormat === 'auto') {
    fmtEl.dataset.locked = '0';
    // 自动识别模式下只显示「自动」，不暴露具体协议
    display = '自动';
  } else {
    display = activeFormat === 'openai' ? 'OpenAI' : 'Anthropic';
  }
  labelEl.textContent = display;
  // 高亮下拉里被选中的项
  document.querySelectorAll('.pf-format-option').forEach(opt => {
    const optFmt = opt.getAttribute('data-format');
    const check = opt.querySelector('.pf-format-check');
    let isActive = false;
    if (activeFormat === 'auto') {
      isActive = optFmt === 'auto';
    } else {
      isActive = optFmt === activeFormat;
    }
    if (check) check.style.display = isActive ? 'inline-block' : 'none';
    if (isActive) {
      opt.style.background = 'var(--accent-light)';
      opt.style.color = 'var(--accent)';
    } else {
      opt.style.background = 'transparent';
      opt.style.color = 'var(--text-primary)';
    }
  });
}

function openProviderEditor(id) {
  if (id) {
    const existing = providerStore.providers.find(x => x.id === id);
    if (existing && isBuiltinProvider(existing)) {
      showCustomAlert('内置供应商不可编辑。', '无法编辑', 'warn');
      return;
    }
  }
  const title = document.getElementById('providerModalTitle');
  const p = id ? providerStore.providers.find(x => x.id === id) : null;
  document.getElementById('pf-id').value = p ? p.id : '';
  document.getElementById('pf-name').value = p ? p.name : '';
  const host = p ? p.apiHost : '';
  const path = p ? (p.apiPath || '') : '';
  const detectedApiFormat = autoDetectFormatFromHost(`${host}${path}`);
  const fmtElInit = document.getElementById('pf-format');
  if (fmtElInit) {
    fmtElInit.value = detectedApiFormat;
    fmtElInit.dataset.locked = '0';
  }

  // Show only the user-facing API URL. Generated default paths stay internal.
  const apiFormat = detectedApiFormat;
  document.getElementById('pf-host').value = p ? providerEndpointDisplayUrl(host, path, apiFormat) : host;
  document.getElementById('pf-path').value = p ? displayProviderApiPath(apiFormat, path) : '';
  document.getElementById('pf-key').value = p ? p.apiKey : '';
  document.getElementById('pf-key').type = 'password';
  const caps = providerCapabilities(p || { apiPath: document.getElementById('pf-path').value });
  const gzipEl = document.getElementById('pf-cap-gzip');
  if (gzipEl) gzipEl.checked = caps.gzip;
  const keyBtn = document.getElementById('pf-key-toggle');
  if (keyBtn) keyBtn.innerHTML = EYE_SVG_OPEN;

  // Load selected models (supports fallback to defaultModel if models array is empty/absent)
  if (p) {
    selectedModels = providerSelectedModels(p);
    editorDraftModelCaps = {};
  } else {
    selectedModels = [];
    editorDraftModelCaps = {};
  }
  updateSelectedModelsUI();

  if (title) title.textContent = p ? '编辑供应商' : '新增供应商';
  const subtitleEl = document.getElementById('providerModalSubtitle');
  if (subtitleEl) subtitleEl.textContent = p ? `正在编辑「${p.name}」` : '配置供应商信息和模型';

  // Start with configured models in list
  activeModelsList = [...selectedModels];
  modelGroupStates = {};
  modelSearchOpen = false;
  currentModelTab = 'all';

  // 重置 UI 的 Tab 选中状态
  document.querySelectorAll('.model-filter-tab').forEach(el => {
    const isAllTab = el.getAttribute('onclick')?.includes("'all'");
    el.classList.toggle('active', !!isAllTab);
  });

  const searchInput = document.getElementById('modelSearchInput');
  if (searchInput) searchInput.value = '';

  onFormatChange();
  // 切到「新增/编辑供应商」普通 page，保持顶部 tab 栏可见
  navigateTo('provider-editor');

  // 注册全局点击关闭 API 格式下拉（首次进入时挂一次）
  if (!window._pfFormatDropdownGlobalBound) {
    window._pfFormatDropdownGlobalBound = true;
    window.addEventListener('click', (e) => {
      const dd = document.getElementById('pfFormatDropdown');
      const select = document.getElementById('pfFormatSelect');
      if (!dd || !select) return;
      if (select.contains(e.target)) return;
      if (dd.style.display === 'flex') {
        dd.style.display = 'none';
        const trigger = document.getElementById('pfFormatTrigger');
        if (trigger) trigger.setAttribute('aria-expanded', 'false');
      }
    });
  }

  // Remote model fetching is manual only. Opening the editor must not call provider APIs.
}

function closeProviderEditor() {
  // 返回供应商列表
  navigateTo('providers');
}

async function saveProviderFromEditor() {
  const id = document.getElementById('pf-id').value;
  if (id) {
    const existing = providerStore.providers.find(x => x.id === id);
    if (existing && isBuiltinProvider(existing)) {
      showCustomAlert('内置供应商不可编辑。', '无法保存', 'warn');
      return;
    }
  }
  const name = document.getElementById('pf-name').value.trim();
  const apiFormat = document.getElementById('pf-format').value;
  const baseUrl = document.getElementById('pf-host').value.trim();
  const apiKey = document.getElementById('pf-key').value.trim();

  if (!name || !baseUrl || !apiKey || selectedModels.length === 0) {
    addLog('warn', '请填写名称、地址、密钥并至少选择一个模型');
    return;
  }

  const { apiHost, apiPath } = providerEndpointParts(
    baseUrl,
    apiFormat,
    document.getElementById('pf-path').value
  );

  const defaultModel = selectedModels[0] || '';
  const existingProvider = id ? providerStore.providers.find(x => x.id === id) : null;
  const existingCaps = existingProvider?.capabilities || {};
  const capabilities = {
    ...existingCaps,
    text: true,
    stream: true,
    vision: existingCaps.vision !== false,
    tools: existingCaps.tools !== false,
    gzip: !!document.getElementById('pf-cap-gzip')?.checked,
  };

  // 合并已有 modelCaps + 本次弹窗探测到的草稿能力
  const existingModelCaps = existingProvider?.modelCaps || {};
  const mergedModelCaps = { ...existingModelCaps, ...editorDraftModelCaps };
  const provider = {
    id: id || `p-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    name, apiHost, apiKey, defaultModel,
    apiPath: apiPath || null,
    enabled: true,
    capabilities,
    models: [...selectedModels],
    modelCaps: mergedModelCaps,
  };
  if (existingProvider?.unlocks) provider.unlocks = existingProvider.unlocks;
  if (existingProvider?.meta) provider.meta = existingProvider.meta;

  const previous = typeof cloneProviderStore === 'function'
    ? cloneProviderStore()
    : JSON.parse(JSON.stringify(providerStore || { version: 1, providers: [] }));
  if (id) {
    const idx = providerStore.providers.findIndex(x => x.id === id);
    if (idx >= 0) {
      provider.enabled = providerStore.providers[idx].enabled !== false;
      providerStore.providers[idx] = provider;
    }
  } else {
    providerStore.providers.push(provider);
  }

  const ok = await persistProviders();
  if (!ok) {
    providerStore = typeof cloneProviderStore === 'function'
      ? cloneProviderStore(previous)
      : JSON.parse(JSON.stringify(previous));
    return;
  }
  renderProviders();
  renderEvalProviderOptions();
  await renderModelMap();
  closeProviderEditor();
  addLog('ok', `已保存供应商: ${name}`);
}

function setProviderConnectionText(id, value) {
  const text = document.getElementById(`conn-text-${id}`);
  if (!text) return;
  const message = String(value || '失败');
  text.textContent = message;
  text.title = message;
  const status = text.closest('.provider-conn-status');
  if (status) status.title = message;
}

async function testProvider(id) {
  if (!invoke) return;
  const p = providerStore.providers.find(x => x.id === id);
  if (!p) return;
  const dot = document.getElementById(`conn-dot-${id}`);
  setProviderConnectionText(id, '测试中…');
  const formats = ['openai', 'anthropic'];
  const results = [];
  const previous = typeof cloneProviderStore === 'function'
    ? cloneProviderStore()
    : JSON.parse(JSON.stringify(providerStore || { version: 1, providers: [] }));
  let storeChanged = false;
  for (const apiFormat of formats) {
    const result = await invoke('test_connection', {
      args: {
        host: p.apiHost, api_key: p.apiKey,
        path: p.apiPath || null,
        api_format: apiFormat,
        model: p.defaultModel || null,
      }
    }).then(value => ({ apiFormat, ok: true, value }), error => ({ apiFormat, ok: false, error }));
    results.push(result);
    if (result.ok && result.value && typeof result.value === 'object' && result.value.capabilities) {
      const idx = providerStore.providers.findIndex(x => x.id === id);
      if (idx >= 0) {
        const c = result.value.capabilities;
        // gzip 是供应商级能力
        if (c.gzip !== undefined) {
          const caps = providerStore.providers[idx].capabilities || {};
          caps.gzip = c.gzip;
          providerStore.providers[idx].capabilities = caps;
        }
        // vision/tools 是模型级能力，仅保存正向探测结果（true）
        // 探测失败(false)不保存，避免误标导致后续图片/工具请求被永久拦截
        const testModel = providerSelectedModels(p)[0] || null;
        if (testModel && (c.vision === true || c.tools === true)) {
          const mc = providerStore.providers[idx].modelCaps || {};
          mc[testModel] = mc[testModel] || {};
          if (c.vision === true) mc[testModel].vision = true;
          if (c.tools === true) mc[testModel].tools = true;
          providerStore.providers[idx].modelCaps = mc;
        }
        storeChanged = true;
      }
    }
  }
  const okResults = results.filter(r => r.ok);
  if (okResults.length) {
    const saved = storeChanged ? await persistProviders() : true;
    if (!saved) {
      providerStore = typeof cloneProviderStore === 'function'
        ? cloneProviderStore(previous)
        : JSON.parse(JSON.stringify(previous));
      if (dot) dot.className = 'conn-dot no';
      setProviderConnectionText(id, '能力保存失败');
      return;
    }
    if (dot) dot.className = 'conn-dot ok';
    const msg = results.map(r => `${r.apiFormat === 'openai' ? 'OpenAI' : 'Anthropic'} ${r.ok ? '✓' : '✗'}`).join(' / ');
    setProviderConnectionText(id, msg);
    addLog('ok', `${p.name} 协议探测: ${msg}`);
  } else {
    if (dot) dot.className = 'conn-dot no';
    const msg = results.map(r => `${r.apiFormat === 'openai' ? 'OpenAI' : 'Anthropic'}: ${String(r.error || '失败').slice(0, 80)}`).join('；');
    setProviderConnectionText(id, '全部失败');
    addLog('err', `${p.name} 协议探测失败: ${msg}`);
  }
}

// ─── 弹窗内测试连接 ──────────────────────────────────────────────
function setProviderEditorTestButtonState(loading) {
  const btn = document.getElementById('provider-editor-test-btn');
  if (!btn) return;
  const label = btn.querySelector('.provider-editor-test-label') || btn.querySelector('span:last-child');
  btn.disabled = !!loading;
  btn.classList.toggle('is-loading', !!loading);
  if (label) label.textContent = loading ? '测试中...' : '测试连接';
}

function showProviderEditorTestToast(message, type = 'info', options = {}) {
  if (typeof showBottomToast === 'function') {
    showBottomToast(message, type, options);
  }
}

async function testProviderInEditor() {
  if (!invoke) {
    showProviderEditorTestToast('应用通道未就绪，无法测试连接', 'error');
    addLog('err', '连接测试失败: Tauri 通道未就绪');
    return;
  }
  const baseUrl = document.getElementById('pf-host').value.trim();
  const apiKey = document.getElementById('pf-key').value.trim();
  const fmt = document.getElementById('pf-format').value;
  const apiPath = document.getElementById('pf-path').value || '';
  const model = selectedModels[0] || null;
  if (!baseUrl || !apiKey) {
    showProviderEditorTestToast('请先填写 API 地址和密钥', 'warn');
    addLog('warn', '请先填写 API 地址和密钥');
    return;
  }
  if (!model) {
    showProviderEditorTestToast('请先选择一个模型作为测试目标', 'warn');
    addLog('warn', '请先选择一个模型作为测试目标');
    return;
  }

  const endpoint = providerEndpointParts(baseUrl, fmt, apiPath || null);

  setProviderEditorTestButtonState(true);
  showProviderEditorTestToast(`正在测试 ${model}...`, 'info', { duration: 1400 });
  try {
    const result = await invoke('test_connection', {
      args: { host: endpoint.apiHost, api_key: apiKey, path: endpoint.apiPath || null, api_format: fmt, model }
    });
    const msg = typeof result === 'string' ? result : (result.message || '连通 ✓');
    // 自动设置探测到的能力标记
    if (result && typeof result === 'object' && result.capabilities) {
      const c = result.capabilities;
      // gzip 是供应商级能力
      const gzipEl = document.getElementById('pf-cap-gzip');
      if (gzipEl && c.gzip !== undefined) gzipEl.checked = c.gzip;
      // vision/tools 是模型级能力：仅保存正向探测（true），失败不覆盖已有标记
      if (model && (c.vision === true || c.tools === true)) {
        editorDraftModelCaps[model] = editorDraftModelCaps[model] || {};
        if (c.vision === true) editorDraftModelCaps[model].vision = true;
        if (c.tools === true) editorDraftModelCaps[model].tools = true;

        const editId = document.getElementById('pf-id')?.value;
        if (editId) {
          const idx = providerStore.providers.findIndex(x => x.id === editId);
          if (idx >= 0) {
            const previous = typeof cloneProviderStore === 'function'
              ? cloneProviderStore()
              : JSON.parse(JSON.stringify(providerStore || { version: 1, providers: [] }));
            const mc = providerStore.providers[idx].modelCaps || {};
            mc[model] = { ...(mc[model] || {}), ...editorDraftModelCaps[model] };
            providerStore.providers[idx].modelCaps = mc;
            const saved = await persistProviders();
            if (!saved) {
              providerStore = typeof cloneProviderStore === 'function'
                ? cloneProviderStore(previous)
                : JSON.parse(JSON.stringify(previous));
              return;
            }
          }
        }
        updateSelectedModelsUI();
      }
    }
    showProviderEditorTestToast(`连接测试通过：${msg}`, 'success', { duration: 3200 });
    addLog('ok', '连接测试: ' + msg);
  } catch (e) {
    const message = String(e) || '失败';
    if (typeof showCustomAlert === 'function') {
      showCustomAlert(message, '连接测试失败', 'error');
    } else {
      showProviderEditorTestToast(`连接测试失败：${message}`, 'error', { duration: 4200 });
    }
    addLog('err', '连接测试失败: ' + e);
  } finally {
    setProviderEditorTestButtonState(false);
  }
}

// ─── 弹窗内拉取模型列表 ──────────────────────────────────────────
async function fetchModelsForEditor(options = {}) {
  if (!invoke) return;
  const baseUrl = document.getElementById('pf-host').value.trim();
  const apiKey = document.getElementById('pf-key').value.trim();
  const apiPath = document.getElementById('pf-path').value || '';
  const fmtEl = document.getElementById('pf-format');
  const primaryFmt = fmtEl ? fmtEl.value : 'anthropic';
  const btn = document.getElementById('pf-fetch-btn');
  const isBackground = !!options.background;
  if (!baseUrl || !apiKey) {
    addLog('warn', '请先填写 API 地址和密钥');
    return;
  }
  if (btn?.dataset.loading === '1') return;
  // 计算尝试顺序：先按当前协议；如失败回退到另一种协议
  const lockedFormat = fmtEl?.dataset?.locked === '1';
  const formatsToTry = lockedFormat
    ? [primaryFmt]
    : (primaryFmt === 'openai' ? ['openai', 'anthropic'] : ['anthropic', 'openai']);
  const fmtLabel = (f) => f === 'openai' ? 'OpenAI' : 'Anthropic';

  let succeeded = null;
  let lastError = null;
  for (let i = 0; i < formatsToTry.length; i++) {
    const tryFmt = formatsToTry[i];
    if (btn) {
      btn.dataset.loading = '1';
      btn.disabled = true;
      btn.innerHTML = providerFetchButtonContent(isBackground
        ? `同步 ${fmtLabel(tryFmt)} 模型…`
        : `用 ${fmtLabel(tryFmt)} 协议拉取中…`, true);
    }
    if (i > 0) {
      addLog('info', `尝试用 ${fmtLabel(tryFmt)} 协议重新拉取…`);
    } else {
      addLog('info', `开始用 ${fmtLabel(tryFmt)} 协议拉取模型列表…`);
    }
    try {
      const endpoint = providerEndpointParts(baseUrl, tryFmt, apiPath || null);
      const result = await invoke('fetch_models', {
        args: {
          host: endpoint.apiHost,
          api_key: apiKey,
          api_format: tryFmt,
          path: endpoint.apiPath || null,
        }
      });
      if (result.models && result.models.length > 0) {
        succeeded = { fmt: tryFmt, models: result.models };
        break;
      } else {
        lastError = new Error(`${fmtLabel(tryFmt)} 协议返回的模型列表为空`);
      }
    } catch (e) {
      lastError = e;
    }
  }

  try {
    if (succeeded) {
      activeModelsList = Array.from(new Set([...selectedModels, ...succeeded.models]));

      // 拉取成功：把下拉/select 同步到真正命中的协议，并锁定（避免下次输入 URL 又被覆盖）
      if (fmtEl) {
        fmtEl.value = succeeded.fmt;
        fmtEl.dataset.locked = '1';
        if (typeof onFormatChange === 'function') onFormatChange();
      }

      // Auto fill first model if empty
      const modelInput = document.getElementById('pf-model');
      if (modelInput && !modelInput.value) {
        selectModel(succeeded.models[0]);
      }

      modelGroupStates = {};
      filterModelPanel();
      addLog('ok', `✅ 用 ${fmtLabel(succeeded.fmt)} 协议成功拉取到 ${succeeded.models.length} 个模型`);
    } else {
      throw lastError || new Error('未知错误');
    }
  } catch (e) {
    // No more default preset list overrides - strictly show what is configured
    addLog('warn', `线上拉取失败 (${e})。你可检查配置、或使用底部输入框手动添加自定义模型 ID。`);
    // Keep local selections visible; a transient remote failure should not make saved models disappear.
    const modelInput = document.getElementById('pf-model');
    const modelVal = modelInput ? modelInput.value : '';
    activeModelsList = Array.from(new Set([...selectedModels, modelVal].filter(Boolean)));
    modelGroupStates = {};
    filterModelPanel();
  } finally {
    if (btn) {
      btn.dataset.loading = '0';
      btn.disabled = false;
      btn.innerHTML = providerFetchButtonContent('获取模型列表');
    }
  }
}
